UPDATE J09B_temp
SET ENTSCHEIDUNG = 'KSA'
WHERE HAUS IN (
  SELECT HAUS FROM (
    SELECT HAUS, COUNT(DISTINCT EQUNR) AS N_EQUNR
    FROM J09B_temp
    GROUP BY HAUS
  ) t
  WHERE N_EQUNR < 3
);

UPDATE J09B_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HAUS IN (
  SELECT HAUS FROM (
    SELECT HAUS, COUNT(DISTINCT EQUNR) AS N_EQUNR
    FROM J09B_temp
    GROUP BY HAUS
  ) t
  WHERE N_EQUNR >= 3
);
